mapper.select:
select * from agents

    and site_id = #{siteId}
    and owner_gateway_node_id = #{ownerGatewayNodeId}
    and status = #{status}
    and status in ('CONNECTED','IDLE','BUSY_ACCEPTING','BUSY') and coalesce(draining,false) = false and (runtime_backoff_until is null or runtime_backoff_until <= now()) and (available_slots > 0 or current_task_count + reserved_task_count < max_concurrent_tasks)

        and (
            capabilities_json @> jsonb_build_array(#{capability})
            or exists (
                select 1
                from agent_runtime_capability_items rci
                where rci.agent_id = agents.agent_id
                  and rci.capability_value = #{capability}
            )
            or capability_profile_json @> jsonb_build_object('supportedCapabilities', jsonb_build_array(#{capability}))
            or capability_profile_json @> jsonb_build_object('runtimeCapabilities', jsonb_build_array(#{capability}))
            or capability_profile_json @> jsonb_build_object('supportedTaskTypes', jsonb_build_array(#{capability}))
            or capability_profile_json @> jsonb_build_object('supportedIssueProviders', jsonb_build_array(#{capability}))
            or capability_profile_json @> jsonb_build_object('toolPolicies', jsonb_build_array(#{capability}))
            or capability_profile_json @> jsonb_build_object('executorMode', #{capability})
        )


order by last_heartbeat_at desc nulls last limit #{limit}
